external_knowledge:
- "identities" refers to the full names of the contacts;
- "corporate affiliations" indicates the companies the contacts are associated with;
- "electronic correspondence details" means the email addresses of the contacts, which may not be present for all entries.

sql:
SELECT * 
FROM interactions 
WHERE contact_id = 12345;

SELECT AVG(total_interactions) AS average_interactions 
FROM (
  SELECT contact_id, COUNT(*) AS total_interactions 
  FROM interactions 
  GROUP BY contact_id
);
